mapper.select:
SELECT uf.user_id, uf.artifact_id, uf.group_name, uf.created_at,
       a.title_zh, a.title_en, a.image_url
FROM user_favorites uf
LEFT JOIN artifacts a ON uf.artifact_id = a.id
WHERE uf.user_id = #{userId}

    AND uf.group_name = #{groupName}

ORDER BY uf.created_at DESC

    LIMIT #{offset}, #{limit}

SELECT uf.user_id, uf.artifact_id, uf.group_name AS groupName, uf.created_at AS createdAt, u.username, u.avatar_url AS userAvatar, a.title_zh AS artifactName, a.image_url AS artifactImage FROM user_favorites uf LEFT JOIN users u ON uf.user_id = u.id LEFT JOIN artifacts a ON uf.artifact_id = a.id
AND u.username LIKE CONCAT('%', #{username}, '%')
AND a.title_zh LIKE CONCAT('%', #{artifactName}, '%')
AND uf.created_at >= #{startTime}
AND uf.created_at <= #{endTime}
ORDER BY uf.created_at DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM user_favorites uf LEFT JOIN users u ON uf.user_id = u.id LEFT JOIN artifacts a ON uf.artifact_id = a.id
AND u.username LIKE CONCAT('%', #{username}, '%')
AND a.title_zh LIKE CONCAT('%', #{artifactName}, '%')
AND uf.created_at >= #{startTime}
AND uf.created_at <= #{endTime}
